using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Shared state for tools ──────────────────────────────────────────────────
var notes = new List<(string Title, string Content)>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// ── Define tools ────────────────────────────────────────────────────────────
var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query")] string query) => SearchWebAsync(query, httpClient),
        name: "search_web",
        description: "Search the web for information. Returns relevant result snippets and URLs."),

    AIFunctionFactory.Create(
        ([Description("URL of the web page to read")] string url) => FetchWebPageAsync(url, httpClient),
        name: "fetch_webpage",
        description: "Fetch and read the text content of a web page at the given URL."),

    AIFunctionFactory.Create(
        ([Description("Short title")] string title,
         [Description("Note content")] string content) =>
        {
            notes.Add((title, content));
            Console.WriteLine($"  📝 Note saved: {title}");
            return $"Note saved: \"{title}\"";
        },
        name: "take_note",
        description: "Save a research note. Use this to record key findings during research."),

    AIFunctionFactory.Create(
        () =>
        {
            if (notes.Count == 0) return "No notes have been saved yet.";
            var sb = new StringBuilder();
            for (int i = 0; i < notes.Count; i++)
            {
                sb.AppendLine($"--- Note {i + 1}: {notes[i].Title} ---");
                sb.AppendLine(notes[i].Content);
                sb.AppendLine();
            }
            return sb.ToString();
        },
        name: "read_notes",
        description: "Read all previously saved research notes."),
};

// ── Configure AI client ─────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_CHAT_MODEL") ?? "gpt-4o-mini";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── Build the research agent ────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a thorough research agent. When given a topic, follow this process:

        1. **Search** – Run at least 3 different web searches covering various angles of the topic.
        2. **Read**   – Fetch the most promising pages to gather detailed information.
        3. **Note**   – After each search/fetch, take notes on key findings (facts, data, sources).
        4. **Synthesize** – Once you have enough material, read your notes and produce a
           well-structured summary with clear sections and source references.

        Always cite sources. Be factual and objective.
        """,
    tools: tools);

// ── Interactive prompt ──────────────────────────────────────────────────────
Console.WriteLine("🔬 Research Agent");
Console.WriteLine("=================");
Console.Write("\nEnter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent ───────────────────────────────────────────────────────────
var session = new AgentSession();
var response = await agent.RunAsync(
    $"Please research the following topic: {topic}", session);

Console.WriteLine("\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");
Console.WriteLine(response.Text);

if (notes.Count > 0)
    Console.WriteLine($"\n📝 {notes.Count} research note(s) were saved during this session.");

// ── Tool implementations ────────────────────────────────────────────────────

static async Task<string> SearchWebAsync(string query, HttpClient http)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        using var res = await http.SendAsync(request);
        res.EnsureSuccessStatusCode();
        var html = await res.Content.ReadAsStringAsync();

        var results = new List<string>();
        var pattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>" +
            @".*?<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline);

        foreach (Match match in pattern.Matches(html))
        {
            if (results.Count >= 8) break;

            var link = WebUtility.HtmlDecode(match.Groups[1].Value.Trim());
            var title = StripHtml(match.Groups[2].Value);
            var snippet = StripHtml(match.Groups[3].Value);

            // DuckDuckGo wraps links in a redirect; extract the actual URL.
            if (link.StartsWith("//duckduckgo.com/l/?uddg="))
            {
                link = Uri.UnescapeDataString(
                    link.Split("uddg=")[1].Split('&')[0]);
            }

            results.Add($"Title: {title}\nURL: {link}\nSnippet: {snippet}");
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found for this query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

static async Task<string> FetchWebPageAsync(string url, HttpClient http)
{
    Console.WriteLine($"  📄 Fetching: {url}");
    try
    {
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        using var res = await http.SendAsync(request);
        res.EnsureSuccessStatusCode();
        var html = await res.Content.ReadAsStringAsync();

        // Strip non-content elements
        html = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ",
            RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<style[^>]*>[\s\S]*?</style>", " ",
            RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<nav[^>]*>[\s\S]*?</nav>", " ",
            RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<footer[^>]*>[\s\S]*?</footer>", " ",
            RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<header[^>]*>[\s\S]*?</header>", " ",
            RegexOptions.IgnoreCase);

        var text = StripHtml(html);
        text = Regex.Replace(text, @"\s+", " ").Trim();

        const int maxLen = 5000;
        if (text.Length > maxLen)
            text = text[..maxLen] + "\n\n[Content truncated…]";

        return string.IsNullOrWhiteSpace(text)
            ? "Could not extract readable content from this page."
            : text;
    }
    catch (Exception ex)
    {
        return $"Failed to fetch page: {ex.Message}";
    }
}

static string StripHtml(string html)
{
    var text = Regex.Replace(html, @"<[^>]+>", " ");
    text = WebUtility.HtmlDecode(text);
    return Regex.Replace(text, @"\s+", " ").Trim();
}

